from pytutor.engine import _UserCodeTestCase

class _UserCodeTestCase(_UserCodeTestCase):
    def test_small(self):
        self.assertEqual(fizzbuzz(5), ["1", "2", "Fizz", "4", "Buzz"])

    def test_15(self):
        out = fizzbuzz(15)
        self.assertEqual(out[2], "Fizz")
        self.assertEqual(out[4], "Buzz")
        self.assertEqual(out[14], "FizzBuzz")
        self.assertEqual(len(out), 15)
